-- Sprint 54: Seed config tables from MSSQL
-- event_timer_show_list (13), send_messages (4), game_master_settings (3), knights_auto (2)

-- event_timer_show_list: 13 rows
ON CONFLICT (id) DO NOTHING;
SELECT setval('event_timer_show_list_id_seq', (SELECT COALESCE(MAX(id), 0) FROM event_timer_show_list));

-- send_messages: 4 rows
ON CONFLICT (id) DO NOTHING;
SELECT setval('send_messages_id_seq', (SELECT COALESCE(MAX(id), 0) FROM send_messages));

-- game_master_settings: 3 rows
ON CONFLICT (char_id) DO NOTHING;

-- knights_auto: 2 rows (default clans)
ON CONFLICT (nation) DO NOTHING;
